    await submitBtn.click();

    await page.waitForURL((url) => !/\/(login|auth|signin)/.test(url.pathname), { timeout: 15000 }).catch(() => {});
    await page.waitForLoadState('load');

    if (/\/(login|auth|signin)/.test(new URL(page.url()).pathname)) {
      test.info().annotations.push({
        type: 'SOURCE_BUG',
        description: 'Login did not redirect away from auth route with provided credentials',
      });
      test.skip(true, 'SOURCE_BUG: authentication failed — cannot reach /patients');
      return;
    }

    await page.goto('http://localhost:3000/patients', { waitUntil: 'domcontentloaded' });
    await page.waitForLoadState('load');

    if (/\/(login|auth|signin)/.test(new URL(page.url()).pathname)) {
      test.info().annotations.push({
        type: 'SOURCE_BUG',
        description: 'Protected /patients route redirected to auth after login',
      });
      test.skip(true, 'SOURCE_BUG: session not persisted to /patients');
      return;
    }

    const body = page.locator('body');
    await expect(body).toBeVisible();

    const searchInput = page
      .getByPlaceholder(/search/i)
      .or(page.getByRole('searchbox'))
      .or(page.getByRole('textbox', { name: /search/i }))
      .or(page.locator('input[type="search"]'))
      .or(page.locator('input[name*="search" i]'))
      .first();

    await searchInput.waitFor({ state: 'visible', timeout: 10000 });

    const rowSelector = '[data-testid*="patient" i], table tbody tr, [role="row"], li[class*="patient" i], [class*="patient-row" i], [class*="patient-item" i]';
    const rowsBefore = page.locator(rowSelector);

    let initialCount = 0;
    try {
      await rowsBefore.first().waitFor({ state: 'visible', timeout: 5000 });
      initialCount = await rowsBefore.count();
    } catch {
      initialCount = 0;
    }

    let searchTerm = 'a';
    if (initialCount > 0) {
      const firstRowText = (await rowsBefore.first().innerText().catch(() => '')) || '';
      const match = firstRowText.match(/[A-Za-z]{2,}/);
      if (match && match[0]) {
        searchTerm = match[0].slice(0, Math.min(4, match[0].length));
      }
    }

    await searchInput.fill(searchTerm);
    await page.waitForTimeout(800);
    await page.waitForLoadState('load');

    const rowsAfter = page.locator(rowSelector);
    const afterCount = await rowsAfter.count();

    if (afterCount === 0 && initialCount === 0) {
      test.info().annotations.push({
        type: 'SOURCE_BUG',
        description: 'No patient rows rendered before or after search — cannot verify filtering',
      });
      test.skip(true, 'SOURCE_BUG: no patient rows present to validate search filter');
      return;
    }

    await expect(searchInput).toHaveValue(searchTerm);

    if (afterCount > 0) {
      const visibleRow = rowsAfter.first();
      await expect(visibleRow).toBeVisible();
      const rowText = (await visibleRow.innerText()).toLowerCase();
      expect(rowText).toContain(searchTerm.toLowerCase());
    } else {
      const emptyIndicator = page
        .getByText(/no (patients|results|records|matches) found/i)
