        .or(page.locator('[data-testid*="empty" i]'))
        .first();
      await expect(emptyIndicator).toBeVisible({ timeout: 5000 });
    }

    expect(afterCount).toBeLessThanOrEqual(initialCount === 0 ? afterCount : initialCount);
  });
});

