import { test, expect } from '@playwright/test';

test.describe('patients — Search patients by name', () => {
  test('TC014 - Search patients by name', async ({ page }) => {
    test.setTimeout(90000);
    const username = process.env.TEST_USERNAME ?? 'testuser';
    const password = process.env.TEST_PASSWORD ?? 'testpass';

    async function login() {
      await page.goto('/login', { waitUntil: 'domcontentloaded' });
      const usernameInput = page.locator('input[name="username"], input[name="email"], input[type="email"]').first();
      const passwordInput = page.locator('input[name="password"], input[type="password"]').first();
      await usernameInput.waitFor({ state: 'visible', timeout: 8000 });
      await usernameInput.fill(username);
      await passwordInput.fill(password);
      const submitBtn = page.locator('button[type="submit"], input[type="submit"]').first();
      await Promise.all([
        page.waitForURL((url) => !/\/(login|auth|signin)/.test(url.pathname), { timeout: 10000 }).catch(() => {}),
        submitBtn.click(),
      ]);
    }

    await login();

    await page.goto('/patients', { waitUntil: 'domcontentloaded' });

    if (/\/(login|auth|signin)/.test(new URL(page.url()).pathname)) {
      await login();
      await page.goto('/patients', { waitUntil: 'domcontentloaded' });
    }

    await expect(page.locator('body')).toBeVisible();

    const searchInput = page.locator(
      'input[type="search"], input[placeholder*="search" i], input[name*="search" i], input[aria-label*="search" i], [role="searchbox"]'
    ).first();

    await searchInput.waitFor({ state: 'visible', timeout: 8000 });

    const rowSelector = '[data-testid*="patient" i], table tbody tr, [role="row"], li[class*="patient" i], [class*="patient-row" i], [class*="patient-item" i]';
    const rowsBefore = page.locator(rowSelector);

    let initialCount = 0;
    try {
      await rowsBefore.first().waitFor({ state: 'visible', timeout: 4000 });
      initialCount = await rowsBefore.count();
    } catch {
      initialCount = 0;
    }

    let searchTerm = 'a';
    if (initialCount > 0) {
      const firstRowText = (await rowsBefore.first().innerText().catch(() => '')) || '';
      const match = firstRowText.match(/[A-Za-z]{2,}/);
      if (match && match[0]) {
        searchTerm = match[0].slice(0, Math.min(4, match[0].length));
      }
    }

    await searchInput.fill(searchTerm);
    await page.waitForTimeout(800);

    const rowsAfter = page.locator(rowSelector);
    const afterCount = await rowsAfter.count();

    await expect(searchInput).toHaveValue(searchTerm);

    if (afterCount > 0) {
      const visibleRow = rowsAfter.first();
      await expect(visibleRow).toBeVisible();
      const rowText = (await visibleRow.innerText()).toLowerCase();
      expect(rowText).toContain(searchTerm.toLowerCase());
      expect(afterCount).toBeLessThanOrEqual(initialCount === 0 ? afterCount : initialCount);
    } else {
      const emptyIndicator = page
        .getByText(/no (patients|results|records|matches) found/i)
        .or(page.getByText(/no data/i))
        .or(page.locator('[data-testid*="empty" i]'))
        .first();
      await expect(emptyIndicator).toBeVisible({ timeout: 4000 });
    }
  });
});

